--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2029,6 +2030,46 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // sub C0, (and (sub C1, X), Mask) --> and X, NewMask
+    // if:
+    //   1. Mask clears a contiguous set of low bits, i.e. ~Mask is a mask.
+    //   2. C1 - C0 is entirely within those cleared low bits.
+    //   3. C0 is aligned to Mask.
+    //
+    // Then:
+    //   (sub C1, X) & Mask == (sub C0, X) & Mask
+    // and:
+    //   C0 - ((C0 - X) & Mask) == X & (((C0 << 1) - 1) & Mask)
+    //
+    // Example:
+    //   sub 64, (and (sub 71, X), -8)
+    //     --> and X, 120
+    {
+      Constant *C1, *MaskC;
+      if (match(Op1, m_And(m_OneUse(m_Sub(m_ImmConstant(C1), m_Value(X))),
+                           m_ImmConstant(MaskC)))) {
+        auto *C0CI = dyn_cast<ConstantInt>(C);
+        auto *C1CI = dyn_cast<ConstantInt>(C1);
+        auto *MaskCI = dyn_cast<ConstantInt>(MaskC);
+        if (C0CI && C1CI && MaskCI && C0CI->getType() == C1CI->getType() &&
+            C0CI->getType() == MaskCI->getType()) {
+          const APInt &C0V = C0CI->getValue();
+          const APInt &C1V = C1CI->getValue();
+          const APInt &MaskV = MaskCI->getValue();
+          APInt LowMask = ~MaskV;
+
+          if (LowMask.isMask()) {
+            APInt Delta = C1V - C0V;
+            if ((Delta & MaskV).isZero() && (C0V & LowMask).isZero()) {
+              APInt NewMask = ((C0V << 1) - 1) & MaskV;
+              return BinaryOperator::CreateAnd(
+                  X, ConstantInt::get(I.getType(), NewMask));
+            }
+          }
+        }
+      }
+    }
   }

   const APInt *Op0C;
@@ -2301,6 +2342,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

